import UIKit

class AppDelegate: UIResponder, UIApplicationDelegate {

    var window: UIWindow?

    func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey : Any] = [:]) -> Bool {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return false
        }
        
        switch components.path {
        case "/profile":
            if let id = components.queryItems?.first(where: { $0.name == "id" })?.value {
                navigateToProfile(withID: id)
            }
        case "/payment/confirm":
            navigateToPaymentConfirmation()
        case "/admin/settings":
            navigateToAdminSettings()
        default:
            return false
        }
        
        return true
    }

    func navigateToProfile(withID id: String) {
        guard let profileVC = window?.rootViewController as? UINavigationController else { return }
        let detailVC = ProfileDetailViewController(id: id)
        profileVC.pushViewController(detailVC, animated: true)
    }

    func navigateToPaymentConfirmation() {
        guard let paymentVC = window?.rootViewController as? UINavigationController else { return }
        let confirmVC = PaymentConfirmationViewController()
        paymentVC.pushViewController(confirmVC, animated: true)
    }

    func navigateToAdminSettings() {
        guard let adminVC = window?.rootViewController as? UINavigationController else { return }
        let settingsVC = AdminSettingsViewController()
        adminVC.pushViewController(settingsVC, animated: true)
    }
}